1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { resolve } from '$app/paths';
4		import { page } from '$app/stores';
5		import ConfirmDialog from '$lib/components/ConfirmDialog.svelte';
6		import Tooltip from '$lib/components/Tooltip.svelte';
7		import { createClient } from '$lib/gql/client';
8		import { PROJECT_QUEUE_SUMMARY_QUERY, WORKER_DISPATCH_MUTATION } from '$lib/gql/feat008';
9		import { CheckCircle2, Loader2, Play, RefreshCcw, ShieldCheck } from 'lucide-svelte';
10		import { onMount } from 'svelte';
11	
12		type ActionId = 'drain' | 'align' | 'checks';
13		type WorkerKind = 'execute-loop' | 'realign-specs' | 'run-checks';
14		type IconComponent = typeof Play;
15	
16		interface QueueSummary {
17			ready: number;
18			blocked: number;
19			inProgress: number;
20		}
21	
22		interface QueueSummaryResult {
23			queueSummary: QueueSummary;
24		}
25	
26		interface WorkerDispatchResult {
27			id: string;
28			state: string;
29			kind: string;
30		}
31	
32		interface WorkerDispatchMutationResult {
33			workerDispatch: WorkerDispatchResult;
34		}
35	
36		interface ProjectAction {
37			id: ActionId;
38			kind: WorkerKind;
39			label: string;
40			shortLabel: string;
41			description: string;
42			Icon: IconComponent;
43			accentClass: string;
44		}
45	
46		const ACTIONS: ProjectAction[] = [
47			{
48				id: 'drain',
49				kind: 'execute-loop',
50				label: 'Drain queue',
51				shortLabel: 'Drain',
52				description: 'Attempt ready beads with the project execute-loop worker.',
53				Icon: Play,
54				accentClass: 'bg-blue-600 text-white hover:bg-blue-700 focus-visible:ring-blue-500'
55			},
56			{
57				id: 'align',
58				kind: 'realign-specs',
59				label: 'Re-align specs',
60				shortLabel: 'Align',
61				description: 'Run the HELIX alignment action against the project spec tree.',
62				Icon: RefreshCcw,
63				accentClass: 'bg-emerald-600 text-white hover:bg-emerald-700 focus-visible:ring-emerald-500'
64			},
65			{
66				id: 'checks',
67				kind: 'run-checks',
68				label: 'Run checks',
69				shortLabel: 'Checks',
70				description: 'Run the project execution definitions and report their result.',
71				Icon: ShieldCheck,
72				accentClass:
73					'bg-gray-950 text-white hover:bg-gray-800 focus-visible:ring-gray-500 dark:bg-white dark:text-gray-950 dark:hover:bg-gray-200'
74			}
75		];
76	
77		let { data }: { data: PageData } = $props();
78	
79		let queueSummary = $state<QueueSummary | null>(null);
80		let queueLoading = $state(true);
81		let alertMessage = $state('');
82		let dialogOpen = $state(false);
83		let activeActionId = $state<ActionId>('drain');
84		let dispatchingActionId = $state<ActionId | null>(null);
85		let dispatchedWorkers = $state<Partial<Record<ActionId, WorkerDispatchResult>>>({});
86		let returnFocusTo = $state<HTMLElement | null>(null);
87	
88		const activeAction = $derived(actionById(activeActionId));
89		const projectName = $derived(data.project?.name ?? $page.params.projectId ?? 'Project');
90		const projectPath = $derived(data.project?.path ?? '');
91	
92		onMount(() => {
93			void loadQueueSummary();
94		});
95	
96		function actionById(id: ActionId): ProjectAction {
97			return ACTIONS.find((action) => action.id === id) ?? ACTIONS[0];
98		}
99	
100		function projectId(): string {
101			return $page.params.projectId ?? data.project?.id ?? '';
102		}
103	
104		function workerHref(workerId: string): string {
105			return resolve('/nodes/[nodeId]/projects/[projectId]/workers/[workerId]', {
106				nodeId: $page.params.nodeId!,
107				projectId: projectId(),
108				workerId
109			});
110		}
111	
112		async function loadQueueSummary() {
113			queueLoading = true;
114			alertMessage = '';
115			try {
116				const client = createClient();
117				const result = await client.request<QueueSummaryResult>(PROJECT_QUEUE_SUMMARY_QUERY, {
118					projectId: projectId()
119				});
120				queueSummary = result.queueSummary;
121			} catch (err) {
122				alertMessage = `Could not load queue summary. ${errorText(err)}`;
123			} finally {
124				queueLoading = false;
125			}
126		}
127	
128		function openDialog(action: ProjectAction, event: MouseEvent) {
129			activeActionId = action.id;
130			returnFocusTo =
131				event.currentTarget instanceof HTMLElement ? event.currentTarget : returnFocusTo;
132			alertMessage = '';
133			dialogOpen = true;
134		}
135	
136		async function confirmDispatch() {
137			const action = activeAction;
138			dispatchingActionId = action.id;
139			alertMessage = '';
140			try {
141				const client = createClient();
142				const result = await client.request<WorkerDispatchMutationResult>(WORKER_DISPATCH_MUTATION, {
143					kind: action.kind,
144					projectId: projectId(),
145					args: actionArgs(action)
146				});
147				dispatchedWorkers = {
148					...dispatchedWorkers,
149					[action.id]: result.workerDispatch
150				};
151			} catch (err) {
152				alertMessage = `${errorText(err)} Try the Workers page to inspect active ${action.kind} workers before dispatching again.`;
153			} finally {
154				dispatchingActionId = null;
155			}
156		}
157	
158		function actionArgs(action: ProjectAction): string {
159			return JSON.stringify({
160				source: 'project-overview-actions',
161				action: action.id
162			});
163		}
164	
165		function disabledReason(action: ProjectAction): string {
166			if (queueLoading) return 'Loading queue summary';
167			if (action.id === 'drain' && (queueSummary?.ready ?? 0) === 0) {
168				return 'No ready beads are available to drain.';
169			}
170			return '';
171		}
172	
173		function queueContext(): string {
174			const summary = queueSummary ?? { ready: 0, blocked: 0, inProgress: 0 };
175			return `${summary.ready} ready ${plural(summary.ready, 'bead')}, ${summary.blocked} blocked, ${summary.inProgress} in progress`;
176		}
177	
178		function actionScope(action: ProjectAction): string {
179			if (action.id === 'drain') {
180				return `${queueSummary?.ready ?? 0} ready ${plural(queueSummary?.ready ?? 0, 'bead')} will be attempted.`;
181			}
182			if (action.id === 'align') {
183				return `The HELIX alignment worker will run with current queue context: ${queueContext()}.`;
184			}
185			return `The project check suite will run with current queue context: ${queueContext()}.`;
186		}
187	
188		function plural(count: number, singular: string): string {
189			return count === 1 ? singular : `${singular}s`;
190		}
191	
192		function errorText(err: unknown): string {
193			if (err instanceof Error) return err.message;
194			if (typeof err === 'string') return err;
195			return 'Unknown error.';
196		}
197	</script>
198	
199	<svelte:head>
200		<title>{projectName} | DDx</title>
201	</svelte:head>
202	
203	<div class="space-y-6">
204		<header class="border-b border-gray-200 pb-6 dark:border-gray-700">
205			<div class="flex flex-wrap items-start justify-between gap-4">
206				<div class="min-w-0">
207					<p class="text-xs font-semibold tracking-widest text-accent-lever dark:text-dark-accent-lever uppercase">
208						Project overview
209					</p>
210					<h1 class="mt-1 text-3xl font-bold tracking-tight text-gray-950 dark:text-white">
211						{projectName}
212					</h1>
213					{#if projectPath}
214						<p class="mt-1 truncate font-mono text-xs text-gray-500 dark:text-gray-400">
215							{projectPath}
216						</p>
217					{/if}
218				</div>
219				<div
220					class="grid min-w-60 grid-cols-3 overflow-hidden rounded-md border border-gray-200 text-center dark:border-gray-700"
221					aria-label="Queue summary"
222				>
223					<div class="px-4 py-3">
224						<div class="text-xl font-semibold text-gray-950 dark:text-white">
225							{queueSummary?.ready ?? '...'}
226						</div>
227						<div class="text-xs text-gray-500 dark:text-gray-400">Ready</div>
228					</div>
229					<div class="border-x border-gray-200 px-4 py-3 dark:border-gray-700">
230						<div class="text-xl font-semibold text-gray-950 dark:text-white">
231							{queueSummary?.blocked ?? '...'}
232						</div>
233						<div class="text-xs text-gray-500 dark:text-gray-400">Blocked</div>
234					</div>
235					<div class="px-4 py-3">
236						<div class="text-xl font-semibold text-gray-950 dark:text-white">
237							{queueSummary?.inProgress ?? '...'}
238						</div>
239						<div class="text-xs text-gray-500 dark:text-gray-400">In progress</div>
240					</div>
241				</div>
242			</div>
243		</header>
244	
245		{#if alertMessage}
246			<div
247				role="alert"
248				class="rounded-md border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-900 dark:border-red-900/70 dark:bg-red-950/30 dark:text-red-100"
249			>
250				{alertMessage}
251			</div>
252		{/if}
253	
254		<section role="region" aria-label="Actions" class="space-y-4">
255			<div class="flex flex-wrap items-center justify-between gap-3 border-b border-gray-200 pb-4 dark:border-gray-700">
256				<div>
257					<h2 class="text-lg font-semibold text-gray-950 dark:text-white">Actions</h2>
258					<p class="mt-1 text-sm text-gray-600 dark:text-gray-300">{queueContext()}</p>
259				</div>
260				<button
261					type="button"
262					onclick={loadQueueSummary}
263					class="rounded-md border border-gray-300 px-3 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:outline-none dark:border-gray-700 dark:text-gray-200 dark:hover:bg-gray-800"
264				>
265					Refresh
266				</button>
267			</div>
268	
269			<div class="grid gap-3 md:grid-cols-3">
270				{#each ACTIONS as action}
271					{@const worker = dispatchedWorkers[action.id]}
272					{@const reason = disabledReason(action)}
273					<div class="rounded-md border border-gray-200 p-3 dark:border-gray-800">
274						<div class="mb-3 flex items-start gap-3">
275							<div
276								class="flex h-9 w-9 shrink-0 items-center justify-center rounded-md bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-200"
277							>
278								<action.Icon class="h-4 w-4" aria-hidden="true" />
279							</div>
280							<div class="min-w-0">
281								<h3 class="font-medium text-gray-950 dark:text-white">{action.label}</h3>
282								<p class="mt-1 text-sm leading-5 text-gray-600 dark:text-gray-300">
283									{action.description}
284								</p>
285							</div>
286						</div>
287	
288						{#if worker}
289							<a
290								href={workerHref(worker.id)}
291								class="inline-flex min-h-10 w-full items-center justify-center gap-2 rounded-md border border-gray-300 px-3 py-2 text-sm font-medium text-gray-900 hover:bg-gray-50 focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:outline-none dark:border-gray-700 dark:text-gray-100 dark:hover:bg-gray-800"
292							>
293								<CheckCircle2 class="h-4 w-4 text-emerald-600 dark:text-emerald-400" />
294								<span>{worker.id}</span>
295							</a>
296						{:else if reason}
297							<Tooltip content={reason} disabledTrigger={true}>
298								<button
299									type="button"
300									aria-disabled="true"
301									class="inline-flex min-h-10 w-full items-center justify-center gap-2 rounded-md bg-gray-200 px-3 py-2 text-sm font-medium text-gray-500 aria-disabled:cursor-not-allowed dark:bg-gray-800 dark:text-gray-500"
302								>
303									{action.label}
304								</button>
305							</Tooltip>
306						{:else}
307							<button
308								type="button"
309								onclick={(event) => openDialog(action, event)}
310								disabled={dispatchingActionId === action.id}
311								class="inline-flex min-h-10 w-full items-center justify-center gap-2 rounded-md px-3 py-2 text-sm font-medium focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-offset-white focus-visible:outline-none disabled:cursor-wait disabled:opacity-80 dark:focus-visible:ring-offset-gray-900 {action.accentClass}"
312							>
313								{#if dispatchingActionId === action.id}
314									<Loader2 class="h-4 w-4 animate-spin" aria-hidden="true" />
315									Starting...
316								{:else}
317									{action.label}
318								{/if}
319							</button>
320						{/if}
321					</div>
322				{/each}
323			</div>
324		</section>
325	</div>
326	
327	<ConfirmDialog
328		bind:open={dialogOpen}
329		actionLabel={`Start ${activeAction.label}`}
330		title={activeAction.label}
331		{returnFocusTo}
332		confirmDisabled={Boolean(disabledReason(activeAction))}
333		onConfirm={confirmDispatch}
334	>
335		{#snippet summary()}
336			<span>{actionScope(activeAction)}</span>
337		{/snippet}
338	
339		<div class="space-y-3">
340			<p>
341				{activeAction.description}
342			</p>
343			<dl class="grid grid-cols-3 gap-2 text-center">
344				<div class="rounded-md bg-gray-100 px-3 py-2 dark:bg-gray-800">
345					<dt class="text-xs text-gray-500 dark:text-gray-400">Ready</dt>
346					<dd class="text-lg font-semibold text-gray-950 dark:text-white">
347						{queueSummary?.ready ?? 0}
348					</dd>
349				</div>
350				<div class="rounded-md bg-gray-100 px-3 py-2 dark:bg-gray-800">
351					<dt class="text-xs text-gray-500 dark:text-gray-400">Blocked</dt>
352					<dd class="text-lg font-semibold text-gray-950 dark:text-white">
353						{queueSummary?.blocked ?? 0}
354					</dd>
355				</div>
356				<div class="rounded-md bg-gray-100 px-3 py-2 dark:bg-gray-800">
357					<dt class="text-xs text-gray-500 dark:text-gray-400">In progress</dt>
358					<dd class="text-lg font-semibold text-gray-950 dark:text-white">
359						{queueSummary?.inProgress ?? 0}
360					</dd>
361				</div>
362			</dl>
363		</div>
364	</ConfirmDialog>
